               "--", "--scene", "dashboard", "--quick", "--no-interactive"])
        .output()
        .expect("Failed to run demo");

    let stdout = String::from_utf8_lossy(&output.stdout);
    info!(stdout_len = stdout.len(), "Captured stdout");

    // Verify expected content
    assert!(stdout.contains("dashboard"), "Missing scene header");
    assert!(stdout.len() > 500, "Dashboard content suspiciously short");

